local function parse_xml_request()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    
    if not body then
        local body_file = ngx.req.get_body_file()
        if body_file then
            local file = io.open(body_file, "r")
            if file then
                body = file:read("*all")
                file:close()
            end
        end
    end
    
    if not body or body == "" then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say('{"error": "Empty request body"}')
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    local success, parsed = pcall(xml.load, body)
    
    if not success then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say('{"error": "Invalid XML format"}')
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    return parsed
end

local function get_element_text(element)
    if type(element) == "string" then
        return element
    end
    
    if type(element) == "table" then
        if element[1] then
            return element[1]
        end
        for _, v in pairs(element) do
